346	  async get(chatId: number, userId?: number): Promise<ChatSession> {
347	    const existing = this.sessions.get(chatId);
348	    if (existing && !existing.client.isClosed) {
349	      existing.lastUsed = Date.now();
350	      return existing;
351	    }
352	    return this.create(chatId, userId);
353	  }
