355	  private async create(chatId: number, userId?: number, providerType?: ProviderType): Promise<ChatSession> {
356	    // Inject TG_ACTIVE_USER_ID so MCP children (mcp-memory) know whose
357	    // facts file to write. MEMORY_DIR is passed through too so the mcp
358	    // server doesn't need to re-read .env.
359	    const env: Record<string, string> = { MEMORY_DIR: config.memoryDir };
360	    if (userId) env.TG_ACTIVE_USER_ID = String(userId);
361	
362	    const activeType = providerType ?? config.defaultProvider;
363	
364	    // Resolve the pinned ACP backend (/agent). Looked up on EVERY create —
365	    // including crash-recreates via get() — so the chosen backend sticks.
366	    let backend: AcpBackendDef | undefined;
367	    if (activeType === "acp") {
368	      const key = this.acpBackendByChat.get(chatId);
369	      if (key) {
370	        backend = loadAcpProviders()[key];
371	        if (!backend) {
372	          console.warn(
373	            `[session ${chatId}] pinned ACP backend "${key}" not in acp-providers.json — falling back to .env agent`,
374	          );
375	          this.acpBackendByChat.delete(chatId);
376	          savePinnedAgents(this.acpBackendByChat).catch(() => {});
377	        }
378	      }
379	    }
380	
381	    const facts = userId ? await loadFacts(userId) : "";
382	
383	    // Try to compress recent facts via local LLM (graceful fallback if unavailable)
384	    let compressed: string | null = null;
385	    if (facts && activeType !== "local") {
386	      const lines = facts.split(/\r?\n/).filter(l => l.trim().length > 0);
387	      const tail = config.memoryPreambleTail;
388	      if (lines.length > tail) {
389	        const { compressFactsForPreamble: compress } = await import("./local-llm.js");
390	        compressed = await compress(lines.slice(-tail));
391	      }
392	    }
393	    const breakdown = activeType === "local"
394	      ? buildLocalPreamble(facts, userId)
395	      : buildPreambleWithBreakdown(facts, userId, { compressed, agentCommand: backend?.command });
396	
397	    // Inject working-state from previous session if available (one-shot).
398	    const wsPath = path.join(config.memoryDir, `working-state-${chatId}.md`);
399	    let workingStateBlock = "";
400	    try {
401	      const ws = await readFile(wsPath, "utf8");
402	      workingStateBlock =
403	        "\n[Previous session working state — use as context to resume work]\n" +
404	        ws +
405	        "\nResume from `next_action` above. Do not ask what was done last time.\n" +
406	        "[End working state]\n\n";
407	      await unlink(wsPath);
408	      console.log(`[session] injected working-state for chat ${chatId}`);
409	    } catch { /* file doesn't exist — normal */ }
410	
411	    // Inject structured session archive restoration (complements working-state
412	    // with turn-level context, goal state, and session stats).
413	    let archiveBlock = "";
414	    let priorArchive: SessionArchive | undefined;
415	    try {
416	      const { loadArchive, buildRestorationBlock, deleteArchive, isArchiveStale } = await import("./session-archive.js");
417	      const archive = await loadArchive(chatId);
418	      if (archive) {
419	        if (isArchiveStale(archive, config.archiveMaxAgeHours, Date.now())) {
420	          const ageH = Math.round((Date.now() - new Date(archive.archivedAt).getTime()) / 3600_000);
421	          // Too old to be a useful handoff. Drop it AND leave priorArchive
422	          // undefined so a trivial close doesn't carry this stale archive
423	          // forward yet again (the root cause of "老是看到很之前的 session").
424	          await deleteArchive(chatId);
425	          console.log(`[session] discarded stale archive for chat ${chatId} (age ${ageH}h > ${config.archiveMaxAgeHours}h)`);
426	        } else {
427	          archiveBlock = "\n" + buildRestorationBlock(archive) + "\n\n";
428	          await deleteArchive(chatId);
429	          priorArchive = archive; // stash for trivial-session carry-forward on close
430	          console.log(`[session] injected session archive for chat ${chatId} (${archive.stats.turnCount} turns, closed=${archive.closeReason})`);
431	        }
432	      }
433	    } catch (err) {
434	      console.error(`[session] loadArchive failed for chat ${chatId}:`, (err as Error).message);
435	    }
436	
437	    // Inject pending dream suggestions (High Priority from last /dream run).
438	    // Read-only：STATE.md 由 dream 每晚重寫，這裡不刪。48h 新鮮度閘門防止
439	    // 注入陳年建議。Frozen-snapshot 合規：只在 create() 組一次，隨 preamble 凍結。
440	    let dreamStateBlock = "";
441	    try {
442	      const { readLoopStateHighPriority, loopStatePath } = await import("./loop-state.js");
443	      const hp = readLoopStateHighPriority();
444	      const fresh = hp?.lastRun && Date.now() - hp.lastRun.getTime() < 48 * 3600_000;
445	      if (hp && fresh && hp.items.length > 0) {
446	        dreamStateBlock =
447	          "\n[Pending dream suggestions — 上次 /dream 維運的 High Priority 待辦]\n" +
448	          hp.items.map((it) => `- ${it}`).join("\n") +
449	          "\n當使用者說「處理建議」「dream 建議」或類似語句時，即指上述項目。\n" +
450	          `完整三層清單（含 Watch List）在 ${loopStatePath()}。處理完某項後，更新該檔移除或標記已處理。\n` +
451	          "[End pending dream suggestions]\n\n";
452	        console.log(`[session] injected ${hp.items.length} pending dream suggestion(s) for chat ${chatId}`);
453	      }
454	    } catch { /* fail-open：STATE.md 缺失或格式不符不影響 session 建立 */ }
455	
456	    const relayTaskBlock = await formatActiveRelayTasksForPreamble(chatId);
457	    const preambleText = breakdown.text + workingStateBlock + archiveBlock + dreamStateBlock + relayTaskBlock;
458	    const agentCommand = backend?.command ?? config.agent.command;
459	    const resumeSessionId = activeType === "acp"
460	      ? await resolveResumeCandidate(chatId, backend, agentCommand)
461	      : undefined;
462	    const provider = this.createProvider(activeType, env, preambleText, backend, resumeSessionId);
463	    const session: ChatSession = {
464	      chatId,
465	      userId,
466	      client: provider,
467	      activeProvider: activeType,
468	      acpBackend: backend?.key,
469	      sessionId: "",
470	      lastUsed: Date.now(),
471	      buffer: "",
472	      toolLog: [],
473	      toolTimeline: [],
474	      stderrTail: "",
475	      history: [],
476	      charsIn: 0,
477	      charsOut: 0,
478	      memoryPreamble: preambleText,
479	      preambleBreakdown: {
480	        total: preambleText.length,
481	        toolNotes: breakdown.toolNotes,
482	        envBlock: breakdown.envBlock,
483	        memoryBlock: breakdown.memoryBlock,
484	        dailylogBlock: breakdown.dailylogBlock,
485	      },
486	      preambleInjected: activeType !== "acp" ? true : false, // Direct providers use system message; ACP needs user-message injection
487	      tailFacts: breakdown.tailFacts,
488	      injectedWikiSlugs: new Set(),
489	      injectedSkills: new Set(),
490	      inflight: false,
491	      _pendingMetaQueue: [],
492	      _consecutiveToolFails: 0,
493	      priorArchive,
494	    };
495	
496	    provider.on("update", (u: SessionUpdate) => this.applyUpdate(session, u));
497	    provider.on("stderr", (chunk) => {
498	      // Keep the tail so we can surface it with error messages.
499	      session.stderrTail = (session.stderrTail + chunk).slice(-2000);
500	      // Surface only when debugging; keep quiet otherwise.
501	      if (process.env.DEBUG_ACP) {
502	        console.error(`[acp ${chatId}] ${chunk.trimEnd()}`);
503	      }
504	    });
505	    provider.on("exit", (code) => {
506	      console.error(`[acp ${chatId}] agent exited (code=${code})`);
507	      // Only fire the unexpected-exit hook if this session is still registered.
508	      // Planned shutdowns (drop/sweepIdle/shutdown) remove it from the map first.
509	      const stillRegistered = this.sessions.get(chatId) === session;
510	      if (stillRegistered) {
511	        this.sessions.delete(chatId);
512	        if (this.onUnexpectedExit) {
513	          this.onUnexpectedExit(session, code).catch((e) =>
514	            console.error(`[session ${chatId}] onUnexpectedExit failed:`, e),
515	          );
516	        }
517	      }
518	    });
519	
520	    session.sessionId = await provider.initialize();
521	
522	    // Resume 成功：context 已在 agent session 內 —— 丟棄本次組好的 preamble
523	    // （不重注，避免雙份）。archive/working-state 已在上方組 preamble 時消費
524	    // 刪除（BC-5 剛好由既有消費點滿足）。breakdown 歸零讓 /context 如實顯示。
525	    const resumed = activeType === "acp" && provider instanceof AcpProvider && provider.resumed;
526	    if (resumed) {
527	      session.memoryPreamble = "";
528	      session.preambleInjected = true;
529	      session.preambleBreakdown = { total: 0, toolNotes: 0, envBlock: 0, memoryBlock: 0, dailylogBlock: 0 };
530	      session.resumed = true;
531	      console.log(`[session ${chatId}] resumed ACP session ${session.sessionId}`);
532	    }
533	    // Registry 生命週期：flag on 時記錄本 session（bridge 整個 crash 也能恢復）
534	    if (config.acpSessionResume && activeType === "acp") {
535	      saveResumable(chatId, {
536	        sessionId: session.sessionId,
537	        backendKey: backend?.key ?? "",
538	        agentCommand,
539	        cwd: config.sessionCwd,
540	        savedAt: Date.now(),
541	      }).catch((err) => console.warn(`[session ${chatId}] saveResumable failed:`, err));
542	    }
543	
544	    this.sessions.set(chatId, session);
545	    logEvent("session_start", { provider: activeType, backend: backend?.key, sessionId: session.sessionId, resumed }, { chatId, userId });
546	    return session;
547	  }
